{
  "hooks": {
    "PreToolUse": [
      {
        "tool_name": "Bash(git push*)",
        "command": "echo 'About to push -- make sure tests pass!'",
        "description": "Warn before any git push command"
      },
      {
        "tool_name": "Write(*.py)",
        "command": "echo 'Writing a Python file'",
        "description": "Log when writing Python files"
      },
      {
        "tool_name": "Edit",
        "command": "echo 'Editing a file'",
        "description": "Log all file edits regardless of path"
      }
    ]
  }
}

{
  "hooks": {
    "PreToolUse": [
      {
        "tool_name": "Bash(rm *)",
        "command": "echo 'BLOCKED: File deletion is not allowed by project hooks.' && exit 2",
        "description": "Block all rm commands to prevent accidental file deletion"
      }
    ]
  }
}

{
  "hooks": {
    "PreToolUse": [
      {
        "tool_name": "Bash",
        "prompt": "Review the command that is about to be executed. If it could delete data, modify system files, or access the network in an unexpected way, warn the user and explain the risk. If it looks safe, say nothing.",
        "description": "Ask Claude to review Bash commands for safety before running"
      }
    ],
    "PostToolUse": [
      {
        "tool_name": "Edit",
        "prompt": "Review the edit that was just made. Check if the code follows the project style conventions. If there are issues, list them briefly.",
        "description": "Auto-review code edits for style compliance"
      }
    ]
  }
}

{
  "hooks": {
    "PostToolUse": [
      {
        "tool_name": "Write(*.{js,ts,jsx,tsx})",
        "command": "npx prettier --write \"\" 2>/dev/null || true",
        "description": "Auto-format JS/TS files with Prettier after writing"
      }
    ],
    "PreToolUse": [
      {
        "tool_name": "Bash(curl *)",
        "command": "echo \"\" | grep -q '| *bash' && echo 'BLOCKED: Piping remote content to shell is not allowed.' && exit 2 || exit 0",
        "description": "Block piping curl output to shell"
      },
      {
        "tool_name": "Bash(chmod 777*)",
        "command": "echo 'BLOCKED: chmod 777 is too permissive. Use specific permissions.' && exit 2",
        "description": "Block overly permissive file permissions"
      }
    ]
  }
}

{
  "hooks": {
    "SessionStart": [
      {
        "command": "echo '--- Session Context ---' && git status --short 2>/dev/null && echo '---' && head -5 .claude/CLAUDE.md 2>/dev/null && echo '---'",
        "description": "Print git status and project context at session start"
      }
    ],
    "PostToolUse": [
      {
        "tool_name": "Edit(*.test.*)",
        "prompt": "A test file was just edited. Remind the user to run the test suite to verify the changes. Suggest the appropriate test command for this project.",
        "description": "Prompt to run tests after editing test files"
      }
    ],
    "PreToolUse": [
      {
        "tool_name": "Write(src/*)",
        "prompt": "A new source file is about to be created. Check: does a similar file already exist in the project? If so, suggest editing the existing file instead of creating a new one.",
        "description": "Prevent duplicate file creation in src directory"
      }
    ]
  }
}
